+        call.invoke(&reg, &[], &mut []).unwrap();
+    }
+
+    #[test]
+    fn invoke_vector_input_output() {
+        unsafe extern "C" fn mock_negate_vec(
+            inputs: *const *const u8,
+            _input_count: usize,
+            outputs: *const *mut u8,
+            _output_count: usize,
